     7→export function generateEdges(def: WorkflowDefinition): WorkflowEdge[] {
     8→  const edges: WorkflowEdge[] = [];
     9→  for (const node of def.nodes) {
    10→    if (!node.next) continue;
    11→    if (typeof node.next === "string") {
    12→      edges.push({
    13→        id: `${node.id}→${node.next}`,
    14→        source: node.id,
    15→        target: node.next,
    16→        sourcePort: "default",
    17→      });
    18→    } else {
    19→      for (const [port, targetId] of Object.entries(node.next)) {
    20→        edges.push({
    21→          id: `${node.id}→${targetId}:${port}`,
    22→          source: node.id,
    23→          target: targetId,
    24→          sourcePort: port,
    25→        });
    26→      }
