    29→  return edges;
    30→}
    31→
    32→/**
    33→ * Find entry nodes — nodes that no other node references via `next`.
    34→ */
    35→export function findEntryNodes(def: WorkflowDefinition): WorkflowNode[] {
    36→  const targets = new Set<string>();
    37→  for (const node of def.nodes) {
    38→    if (!node.next) continue;
    39→    if (typeof node.next === "string") {
    40→      targets.add(node.next);
    41→    } else {
    42→      for (const targetId of Object.values(node.next)) {
    43→        targets.add(targetId);
    44→      }
    45→    }
    46→  }
    47→  return def.nodes.filter((n) => !targets.has(n.id));
    48→}
    49→
    50→/**
    51→ * Get successor node IDs for a given node and port.
    52→ */
    53→export function getSuccessors(
    54→  def: WorkflowDefinition,
    55→  nodeId: string,
    56→  port?: string,
    57→): WorkflowNode[] {
    58→  const node = def.nodes.find((n) => n.id === nodeId);
    59→  if (!node?.next) return [];
    60→
    61→  const targetIds: string[] = [];
    62→  if (typeof node.next === "string") {
    63→    // Single next — any port matches
    64→    targetIds.push(node.next);
    65→  } else {
    66→    if (port) {
    67→      // Port-based — look up the specific port
    68→      const targetId = node.next[port];
    69→      if (targetId) targetIds.push(targetId);
    70→    } else {
    71→      // No port specified — return all targets
    72→      targetIds.push(...Object.values(node.next));
    73→    }
    74→  }
