    90→export function validateDefinition(
    91→  def: WorkflowDefinition,
    92→  registry?: ExecutorRegistry,
    93→): { valid: boolean; errors: string[] } {
    94→  const errors: string[] = [];
    95→  const nodeIds = new Set(def.nodes.map((n) => n.id));
    96→
    97→  // 1. Check all next refs point to existing nodes
    98→  for (const node of def.nodes) {
    99→    if (!node.next) continue;
   100→    if (typeof node.next === "string") {
