   134→      if (typeof node.next === "string") {
   135→        queue.push(node.next);
   136→      } else {
   137→        queue.push(...Object.values(node.next));
   138→      }
   139→    }
   140→    for (const node of def.nodes) {
   141→      if (!reachable.has(node.id)) {
   142→        errors.push(`Node "${node.id}" is unreachable from the entry node`);
   143→      }
   144→    }
   145→  }
   146→
   147→  // 4. Check all node types are registered (if registry provided)
   148→  if (registry) {
   149→    for (const node of def.nodes) {
