// Create content-agent-style workflows via HTTP API
const API = "http://localhost:3015";
const AUTH = "Authorization: Bearer 123123";
const headers = { [AUTH.split(": ")[0]]: AUTH.split(": ")[1], "Content-Type": "application/json" };

async function createWorkflow(data: any) {
  const res = await fetch(`${API}/api/workflows`, {
    method: "POST",
    headers,
    body: JSON.stringify(data),
  });
  const json = await res.json();
  console.log(`  Created: ${data.name} → ${json.id}`);
  return json.id;
}

async function main() {
  console.log("Creating content-agent workflows...\n");

  // 1. Daily Blog Generation
  // Simplified: research → write → notify (per series, sequential)
  await createWorkflow({
    name: "daily-blog-generation",
    description: "Generate daily blog posts for 4 series (Foundation, Test Wars, Vibe, Level Up). Research topic, write content, extract image prompt, then notify.",
    definition: {
      nodes: [
        {
          id: "research-foundation",
          type: "agent-task",
          config: {
            template: "Research a blog topic for the 'Foundation' series. Find a trending topic in software testing fundamentals. Return a JSON with: title, angle, key_points (3-5), target_keywords (3-5), and a one_liner summary.",
            tags: ["content", "research", "foundation"],
          },
          next: "write-foundation",
        },
        {
          id: "write-foundation",
          type: "agent-task",
          config: {
            template: "Write a blog post for the 'Foundation' series based on this research: {{research-foundation.taskOutput}}. The post should be 800-1200 words, SEO-optimized, with clear headings and a compelling introduction. Include a METADATA block with slug, title, description, and keywords.",
            tags: ["content", "writing", "foundation"],
          },
          validation: {
            executor: "validate",
            config: {
              targetNodeId: "write-foundation",
              prompt: "Check if the blog post has: 1) A METADATA block with slug/title/description, 2) At least 800 words, 3) Clear section headings, 4) A compelling introduction. Return pass=true if all criteria met.",
            },
            mustPass: true,
          },
          retry: { maxRetries: 1, strategy: "static", baseDelayMs: 5000 },
          next: "research-test-wars",
        },
        {
          id: "research-test-wars",
          type: "agent-task",
          config: {
            template: "Research a blog topic for the 'Test Wars' series. Find a trending debate or comparison in the testing world (e.g., unit vs integration, TDD vs BDD, manual vs automated). Return a JSON with: title, angle, key_points (3-5), target_keywords (3-5), and a one_liner summary.",
            tags: ["content", "research", "test-wars"],
          },
          next: "write-test-wars",
        },
        {
          id: "write-test-wars",
          type: "agent-task",
          config: {
            template: "Write a blog post for the 'Test Wars' series based on this research: {{research-test-wars.taskOutput}}. The post should present both sides of the debate, 800-1200 words, with a balanced conclusion. Include a METADATA block.",
            tags: ["content", "writing", "test-wars"],
          },
          validation: {
            executor: "validate",
            config: {
              targetNodeId: "write-test-wars",
              prompt: "Check if the blog post has: 1) A METADATA block, 2) At least 800 words, 3) Presents both sides of a debate, 4) Has a balanced conclusion.",
            },
            mustPass: true,
          },
          retry: { maxRetries: 1, strategy: "static", baseDelayMs: 5000 },
          next: "research-vibe",
        },
        {
          id: "research-vibe",
          type: "agent-task",
          config: {
            template: "Research a blog topic for the 'Vibe' series. Find a thought-provoking opinion piece topic about developer culture, productivity, or the future of software development. Return a JSON with: title, angle, key_points (3-5), target_keywords (3-5), and a one_liner summary.",
            tags: ["content", "research", "vibe"],
          },
          next: "write-vibe",
        },
        {
          id: "write-vibe",
          type: "agent-task",
          config: {
            template: "Write a blog post for the 'Vibe' series based on this research: {{research-vibe.taskOutput}}. This should be a more casual, opinion-driven piece, 600-1000 words. Include a METADATA block.",
            tags: ["content", "writing", "vibe"],
          },
          next: "research-level-up",
        },
        {
          id: "research-level-up",
          type: "agent-task",
          config: {
            template: "Research a blog topic for the 'Level Up' series. Find a practical migration or upgrade guide topic (e.g., migrating from Jest to Vitest, upgrading testing frameworks, adopting new CI/CD practices). Return a JSON with: title, angle, key_points (3-5), target_keywords (3-5), and a one_liner summary.",
            tags: ["content", "research", "level-up"],
          },
          next: "write-level-up",
        },
        {
          id: "write-level-up",
          type: "agent-task",
          config: {
            template: "Write a blog post for the 'Level Up' series based on this research: {{research-level-up.taskOutput}}. This should be a step-by-step migration guide, 1000-1500 words, with code examples where relevant. Include a METADATA block.",
            tags: ["content", "writing", "level-up"],
          },
          next: "notify-complete",
        },
        {
          id: "notify-complete",
          type: "notify",
          config: {
            channel: "swarm",
            template: "Daily blog generation complete. 4 posts written: Foundation, Test Wars, Vibe, Level Up.",
          },
        },
      ],
    },
    cooldown: { hours: 12 },
  });

  // 2. Competitor Blog Post
  await createWorkflow({
    name: "competitor-blog-post",
    description: "Research a competitor and generate a comparison blog post with QA validation and SEO optimization.",
    definition: {
      nodes: [
        {
          id: "research-competitor",
          type: "agent-task",
          config: {
            template: "Research the competitor company. Analyze their product, pricing, features, strengths, and weaknesses. Use web search to gather recent information. Return a structured research report in markdown format.",
            tags: ["content", "research", "competitor"],
          },
          next: "draft-blog",
        },
        {
          id: "draft-blog",
          type: "agent-task",
          config: {
            template: "Write a competitor comparison blog post based on this research: {{research-competitor.taskOutput}}. The post should be balanced, highlighting both products' strengths. Include SEO keywords and a clear call-to-action. Target 1000-1500 words.",
            tags: ["content", "writing", "competitor"],
          },
          next: "qa-content",
        },
        {
          id: "qa-content",
          type: "agent-task",
          config: {
            template: "QA review this blog post for: 1) Factual accuracy, 2) Brand voice consistency, 3) SEO optimization, 4) Grammar and spelling, 5) Call-to-action effectiveness. Blog content: {{draft-blog.taskOutput}}. Return a QA report with pass/fail and specific feedback.",
            tags: ["content", "qa"],
          },
          validation: {
            executor: "validate",
            config: {
              targetNodeId: "qa-content",
              prompt: "Check if the QA report indicates the content passes quality standards. Return pass=true if no critical issues were found.",
            },
            mustPass: true,
          },
          next: "seo-optimize",
        },
        {
          id: "seo-optimize",
          type: "agent-task",
          config: {
            template: "SEO-optimize this blog post based on the QA feedback. Original post: {{draft-blog.taskOutput}}. QA feedback: {{qa-content.taskOutput}}. Apply improvements and return the final optimized version.",
            tags: ["content", "seo"],
          },
          next: "notify-done",
        },
        {
          id: "notify-done",
          type: "notify",
          config: {
            channel: "swarm",
            template: "Competitor blog post pipeline complete. SEO-optimized post ready for review.",
          },
        },
      ],
    },
    cooldown: { hours: 23 },
  });

  // 3. Content Refresh (AEO Enhancement)
  await createWorkflow({
    name: "content-refresh-aeo",
    description: "Enhance existing blog posts with AEO elements: answer capsules, statistics, FAQs. Selects posts needing refresh and enhances them in batch.",
    definition: {
      nodes: [
        {
          id: "select-posts",
          type: "script",
          config: {
            runtime: "bash",
            script: "echo '{\"selected_count\": 3, \"posts\": [{\"slug\": \"testing-fundamentals\", \"title\": \"Testing Fundamentals\", \"series_name\": \"Foundation\", \"effective_age_days\": 35}, {\"slug\": \"tdd-vs-bdd\", \"title\": \"TDD vs BDD\", \"series_name\": \"Test Wars\", \"effective_age_days\": 42}, {\"slug\": \"dev-productivity\", \"title\": \"Developer Productivity\", \"series_name\": \"Vibe\", \"effective_age_days\": 38}]}'",
          },
          next: "enhance-batch",
        },
        {
          id: "enhance-batch",
          type: "agent-task",
          config: {
            template: "Enhance these blog posts with AEO (Answer Engine Optimization) elements. For each post, add: 1) Answer capsules (120-150 char summaries after question headings), 2) Statistics with source citations, 3) FAQ section (3-5 relevant FAQs), 4) Updated dateModified. Posts to enhance: {{select-posts.stdout}}",
            tags: ["content", "aeo", "refresh"],
          },
          validation: {
            executor: "validate",
            config: {
              targetNodeId: "enhance-batch",
              prompt: "Verify the AEO enhancements include: 1) Answer capsules, 2) At least 2 statistics with citations, 3) FAQ section with 3+ questions. Return pass=true if all criteria met.",
            },
            mustPass: true,
          },
          retry: { maxRetries: 1, strategy: "static", baseDelayMs: 5000 },
          next: "notify-refresh",
        },
        {
          id: "notify-refresh",
          type: "notify",
          config: {
            channel: "swarm",
            template: "AEO content refresh complete. Enhanced posts ready for PR review.",
          },
        },
      ],
    },
    cooldown: { hours: 15 },
  });

  // 4. How-To Guide Generation
  await createWorkflow({
    name: "how-to-guide-generation",
    description: "Generate comprehensive how-to guides for product features. Research feature, write guide, convert to page format.",
    definition: {
      nodes: [
        {
          id: "generate-guide",
          type: "agent-task",
          config: {
            template: "Generate a comprehensive how-to guide for a product feature. The guide should include: 1) Prerequisites, 2) Step-by-step instructions with screenshots/code, 3) Common pitfalls, 4) Best practices, 5) Related features. Target 1500-2000 words in markdown format.",
            tags: ["content", "how-to", "guide"],
          },
          next: "convert-to-page",
        },
        {
          id: "convert-to-page",
          type: "agent-task",
          config: {
            template: "Convert this how-to guide into a production-ready page format (TSX/MDX). Add proper metadata, navigation, and styling. Guide content: {{generate-guide.taskOutput}}",
            tags: ["content", "conversion"],
          },
          next: "notify-guide",
        },
        {
          id: "notify-guide",
          type: "notify",
          config: {
            channel: "swarm",
            template: "How-to guide generated and converted. Ready for PR.",
          },
        },
      ],
    },
    cooldown: { hours: 312 },
  });

  // 5. Local SEO Content
  await createWorkflow({
    name: "local-seo-content",
    description: "Generate geo-targeted content for local business pages. Creates location-specific landing pages with local SEO optimization.",
    definition: {
      nodes: [
        {
          id: "generate-local",
          type: "agent-task",
          config: {
            template: "Generate geo-targeted local SEO content for a city/region. Include: 1) Location-specific pain points, 2) Local market context, 3) Relevant local statistics, 4) Location-aware CTAs, 5) Structured data for local SEO. Target keywords: QA testing, automated testing, software quality. Output in markdown.",
            tags: ["content", "local-seo"],
          },
          next: "create-page",
        },
        {
          id: "create-page",
          type: "agent-task",
          config: {
            template: "Convert this local SEO content into a production-ready landing page (TSX). Include proper geo meta tags, structured data (LocalBusiness schema), and location-specific imagery placeholders. Content: {{generate-local.taskOutput}}",
            tags: ["content", "conversion", "local-seo"],
          },
          next: "notify-local",
        },
        {
          id: "notify-local",
          type: "notify",
          config: {
            channel: "swarm",
            template: "Local SEO page generated. Ready for PR and deployment.",
          },
        },
      ],
    },
    cooldown: { hours: 696 },
  });

  // 6. Release Notes Generation
  await createWorkflow({
    name: "release-notes-generation",
    description: "Generate weekly release notes from repository commits. Pulls changes, evaluates significance, plans content approach, writes release post.",
    definition: {
      nodes: [
        {
          id: "get-commits",
          type: "script",
          config: {
            runtime: "bash",
            script: "echo 'Recent commits placeholder: feat: added new workflow engine, fix: resolved checkpoint race condition, docs: updated API reference'",
          },
          next: "evaluate-commits",
        },
        {
          id: "evaluate-commits",
          type: "agent-task",
          config: {
            template: "Evaluate these git commits for release note significance. Categorize each as: major feature, minor improvement, bug fix, or internal change. Determine if there's enough material for a release post. Commits: {{get-commits.stdout}}",
            tags: ["content", "release-notes", "evaluation"],
          },
          next: "check-significance",
        },
        {
          id: "check-significance",
          type: "property-match",
          config: {
            conditions: [
              { field: "evaluate-commits.taskOutput", op: "exists", value: true },
            ],
          },
          next: { "true": "plan-content", "false": "skip-notify" },
        },
        {
          id: "plan-content",
          type: "agent-task",
          config: {
            template: "Plan the release notes approach based on commit evaluation: {{evaluate-commits.taskOutput}}. Decide: 1) Main narrative angle, 2) Which changes to highlight, 3) Business value framing, 4) Target audience messaging. Return a structured plan.",
            tags: ["content", "release-notes", "planning"],
          },
          validation: {
            executor: "validate",
            config: {
              targetNodeId: "plan-content",
              prompt: "Verify the release plan includes: 1) A clear narrative angle, 2) At least 2 highlighted changes, 3) Business value framing. Return pass=true if complete.",
            },
            mustPass: true,
          },
          retry: { maxRetries: 2, strategy: "static", baseDelayMs: 5000 },
          next: "write-release",
        },
        {
          id: "write-release",
          type: "agent-task",
          config: {
            template: "Write release notes based on this plan: {{plan-content.taskOutput}}. Include: 1) Executive summary, 2) What's new section with details, 3) Business impact, 4) AEO-optimized structure (answer capsules, statistics), 5) FAQ section. Format as a blog post, 800-1200 words.",
            tags: ["content", "release-notes", "writing"],
          },
          validation: {
            executor: "validate",
            config: {
              targetNodeId: "write-release",
              prompt: "Verify the release notes have: 1) Executive summary, 2) What's new section, 3) At least 1 statistic, 4) FAQ section. Return pass=true if all present.",
            },
            mustPass: true,
          },
          retry: { maxRetries: 1, strategy: "static", baseDelayMs: 5000 },
          next: "notify-release",
        },
        {
          id: "notify-release",
          type: "notify",
          config: {
            channel: "swarm",
            template: "Release notes generated. Post ready for review and PR creation.",
          },
        },
        {
          id: "skip-notify",
          type: "notify",
          config: {
            channel: "swarm",
            template: "Release notes skipped — insufficient changes for a release post this week.",
          },
        },
      ],
    },
    cooldown: { hours: 144 },
  });

  console.log("\nAll 6 content workflows created!");
}

