        {
          id: "write-test-wars",
          type: "agent-task",
          config: {
            template: "Write a blog post for the 'Test Wars' series based on this research: {{research-test-wars.taskOutput}}. The post should present both sides of the debate, 800-1200 words, with a balanced conclusion. Include a METADATA block.",
            tags: ["content", "writing", "test-wars"],
          },
          validation: {
            executor: "validate",
            config: {
              targetNodeId: "write-test-wars",
              prompt: "Check if the blog post has: 1) A METADATA block, 2) At least 800 words, 3) Presents both sides of a debate, 4) Has a balanced conclusion.",
            },
            mustPass: true,
          },
          retry: { maxRetries: 1, strategy: "static", baseDelayMs: 5000 },
          next: "research-vibe",
        },
        {
          id: "research-vibe",
          type: "agent-task",
          config: {
            template: "Research a blog topic for the 'Vibe' series. Find a thought-provoking opinion piece topic about developer culture, productivity, or the future of software development. Return a JSON with: title, angle, key_points (3-5), target_keywords (3-5), and a one_liner summary.",
