            tags: ["content", "writing", "vibe"],
          },
          next: "research-level-up",
        },
        {
          id: "research-level-up",
          type: "agent-task",
          config: {
            template: "Research a blog topic for the 'Level Up' series. Find a practical migration or upgrade guide topic (e.g., migrating from Jest to Vitest, upgrading testing frameworks, adopting new CI/CD practices). Return a JSON with: title, angle, key_points (3-5), target_keywords (3-5), and a one_liner summary.",
            tags: ["content", "research", "level-up"],
          },
          next: "write-level-up",
        },
        {
          id: "write-level-up",
          type: "agent-task",
          config: {
            template: "Write a blog post for the 'Level Up' series based on this research: {{research-level-up.taskOutput}}. This should be a step-by-step migration guide, 1000-1500 words, with code examples where relevant. Include a METADATA block.",
            tags: ["content", "writing", "level-up"],
