    name: "competitor-blog-post",
    description: "Research a competitor and generate a comparison blog post with QA validation and SEO optimization.",
    definition: {
      nodes: [
        {
          id: "research-competitor",
          type: "agent-task",
          config: {
            template: "Research the competitor company. Analyze their product, pricing, features, strengths, and weaknesses. Use web search to gather recent information. Return a structured research report in markdown format.",
            tags: ["content", "research", "competitor"],
          },
          next: "draft-blog",
        },
        {
          id: "draft-blog",
          type: "agent-task",
          config: {
            template: "Write a competitor comparison blog post based on this research: {{research-competitor.taskOutput}}. The post should be balanced, highlighting both products' strengths. Include SEO keywords and a clear call-to-action. Target 1000-1500 words.",
            tags: ["content", "writing", "competitor"],
          },
          next: "qa-content",
        },
        {
          id: "qa-content",
          type: "agent-task",
          config: {
            template: "QA review this blog post for: 1) Factual accuracy, 2) Brand voice consistency, 3) SEO optimization, 4) Grammar and spelling, 5) Call-to-action effectiveness. Blog content: {{draft-blog.taskOutput}}. Return a QA report with pass/fail and specific feedback.",
            tags: ["content", "qa"],
          },
          validation: {
            executor: "validate",
            config: {
              targetNodeId: "qa-content",
              prompt: "Check if the QA report indicates the content passes quality standards. Return pass=true if no critical issues were found.",
            },
            mustPass: true,
          },
          next: "seo-optimize",
        },
        {
          id: "seo-optimize",
          type: "agent-task",
          config: {
            template: "SEO-optimize this blog post based on the QA feedback. Original post: {{draft-blog.taskOutput}}. QA feedback: {{qa-content.taskOutput}}. Apply improvements and return the final optimized version.",
