          type: "agent-task",
          config: {
            template: "Enhance these blog posts with AEO (Answer Engine Optimization) elements. For each post, add: 1) Answer capsules (120-150 char summaries after question headings), 2) Statistics with source citations, 3) FAQ section (3-5 relevant FAQs), 4) Updated dateModified. Posts to enhance: {{select-posts.stdout}}",
            tags: ["content", "aeo", "refresh"],
          },
          validation: {
            executor: "validate",
            config: {
              targetNodeId: "enhance-batch",
              prompt: "Verify the AEO enhancements include: 1) Answer capsules, 2) At least 2 statistics with citations, 3) FAQ section with 3+ questions. Return pass=true if all criteria met.",
            },
            mustPass: true,
          },
          retry: { maxRetries: 1, strategy: "static", baseDelayMs: 5000 },
          next: "notify-refresh",
        },
        {
          id: "notify-refresh",
          type: "notify",
          config: {
            channel: "swarm",
            template: "AEO content refresh complete. Enhanced posts ready for PR review.",
          },
        },
      ],
    },
    cooldown: { hours: 15 },
  });

  // 4. How-To Guide Generation
  await createWorkflow({
    name: "how-to-guide-generation",
    description: "Generate comprehensive how-to guides for product features. Research feature, write guide, convert to page format.",
    definition: {
      nodes: [
        {
          id: "generate-guide",
          type: "agent-task",
          config: {
            template: "Generate a comprehensive how-to guide for a product feature. The guide should include: 1) Prerequisites, 2) Step-by-step instructions with screenshots/code, 3) Common pitfalls, 4) Best practices, 5) Related features. Target 1500-2000 words in markdown format.",
            tags: ["content", "how-to", "guide"],
          },
          next: "convert-to-page",
        },
        {
          id: "convert-to-page",
          type: "agent-task",
          config: {
            template: "Convert this how-to guide into a production-ready page format (TSX/MDX). Add proper metadata, navigation, and styling. Guide content: {{generate-guide.taskOutput}}",
            tags: ["content", "conversion"],
          },
          next: "notify-guide",
        },
        {
          id: "notify-guide",
          type: "notify",
          config: {
            channel: "swarm",
            template: "How-to guide generated and converted. Ready for PR.",
          },
        },
      ],
    },
    cooldown: { hours: 312 },
  });

  // 5. Local SEO Content
  await createWorkflow({
    name: "local-seo-content",
    description: "Generate geo-targeted content for local business pages. Creates location-specific landing pages with local SEO optimization.",
    definition: {
      nodes: [
        {
          id: "generate-local",
          type: "agent-task",
          config: {
            template: "Generate geo-targeted local SEO content for a city/region. Include: 1) Location-specific pain points, 2) Local market context, 3) Relevant local statistics, 4) Location-aware CTAs, 5) Structured data for local SEO. Target keywords: QA testing, automated testing, software quality. Output in markdown.",
            tags: ["content", "local-seo"],
          },
          next: "create-page",
        },
        {
          id: "create-page",
          type: "agent-task",
          config: {
            template: "Convert this local SEO content into a production-ready landing page (TSX). Include proper geo meta tags, structured data (LocalBusiness schema), and location-specific imagery placeholders. Content: {{generate-local.taskOutput}}",
            tags: ["content", "conversion", "local-seo"],
          },
          next: "notify-local",
        },
        {
          id: "notify-local",
          type: "notify",
          config: {
            channel: "swarm",
            template: "Local SEO page generated. Ready for PR and deployment.",
          },
        },
      ],
    },
    cooldown: { hours: 696 },
  });

  // 6. Release Notes Generation
  await createWorkflow({
    name: "release-notes-generation",
    description: "Generate weekly release notes from repository commits. Pulls changes, evaluates significance, plans content approach, writes release post.",
    definition: {
      nodes: [
        {
          id: "get-commits",
          type: "script",
          config: {
            runtime: "bash",
            script: "echo 'Recent commits placeholder: feat: added new workflow engine, fix: resolved checkpoint race condition, docs: updated API reference'",
          },
          next: "evaluate-commits",
        },
        {
          id: "evaluate-commits",
          type: "agent-task",
          config: {
            template: "Evaluate these git commits for release note significance. Categorize each as: major feature, minor improvement, bug fix, or internal change. Determine if there's enough material for a release post. Commits: {{get-commits.stdout}}",
            tags: ["content", "release-notes", "evaluation"],
          },
          next: "check-significance",
        },
        {
          id: "check-significance",
          type: "property-match",
          config: {
            conditions: [
              { field: "evaluate-commits.taskOutput", op: "exists", value: true },
            ],
          },
          next: { "true": "plan-content", "false": "skip-notify" },
        },
        {
          id: "plan-content",
          type: "agent-task",
          config: {
            template: "Plan the release notes approach based on commit evaluation: {{evaluate-commits.taskOutput}}. Decide: 1) Main narrative angle, 2) Which changes to highlight, 3) Business value framing, 4) Target audience messaging. Return a structured plan.",
            tags: ["content", "release-notes", "planning"],
          },
          validation: {
            executor: "validate",
            config: {
              targetNodeId: "plan-content",
              prompt: "Verify the release plan includes: 1) A clear narrative angle, 2) At least 2 highlighted changes, 3) Business value framing. Return pass=true if complete.",
            },
            mustPass: true,
          },
          retry: { maxRetries: 2, strategy: "static", baseDelayMs: 5000 },
          next: "write-release",
        },
        {
          id: "write-release",
          type: "agent-task",
          config: {
            template: "Write release notes based on this plan: {{plan-content.taskOutput}}. Include: 1) Executive summary, 2) What's new section with details, 3) Business impact, 4) AEO-optimized structure (answer capsules, statistics), 5) FAQ section. Format as a blog post, 800-1200 words.",
            tags: ["content", "release-notes", "writing"],
          },
          validation: {
            executor: "validate",
            config: {
              targetNodeId: "write-release",
              prompt: "Verify the release notes have: 1) Executive summary, 2) What's new section, 3) At least 1 statistic, 4) FAQ section. Return pass=true if all present.",
            },
            mustPass: true,
          },
          retry: { maxRetries: 1, strategy: "static", baseDelayMs: 5000 },
          next: "notify-release",
        },
        {
          id: "notify-release",
          type: "notify",
          config: {
            channel: "swarm",
            template: "Release notes generated. Post ready for review and PR creation.",
          },
        },
        {
          id: "skip-notify",
          type: "notify",
          config: {
            channel: "swarm",
            template: "Release notes skipped — insufficient changes for a release post this week.",
          },
        },
      ],
    },
    cooldown: { hours: 144 },
  });

  console.log("\nAll 6 content workflows created!");
}

main().catch(console.error);

