          </InspectorSection>
        )}

        {/* Output Schema (from executor) */}
        {executorInfo?.outputSchema && (
          <InspectorSection label="Output Schema">
            <JsonTree data={executorInfo.outputSchema} defaultExpandDepth={2} maxHeight="200px" />
          </InspectorSection>
        )}

        {/* Next */}
        {node.next != null && (
          <InspectorSection label="Next">
            <JsonTree data={node.next} defaultExpandDepth={2} maxHeight="150px" />
          </InspectorSection>
        )}

        {/* Validation */}
        {node.validation != null && (
          <InspectorSection label="Validation">
            <JsonTree data={node.validation} defaultExpandDepth={2} maxHeight="200px" />
          </InspectorSection>
