  1→import type { Edge, Node } from "@xyflow/react";
  2→import dagre from "dagre";
  3→import type {
  4→  WorkflowDefinition,
  5→  WorkflowEdge,
  6→  WorkflowNode,
  7→  WorkflowNodeType,
  8→  WorkflowRunStep,
  9→  WorkflowRunStepStatus,
 10→} from "@/api/types";
 11→
 12→const CONDITION_TYPES = new Set(["property-match", "code-match", "validate", "raw-llm"]);
 13→export type NodeCategory = "triggerNode" | "conditionNode" | "actionNode";
 14→
 15→export function getNodeCategory(type: WorkflowNodeType): NodeCategory {
 16→  if (type.startsWith("trigger-")) return "triggerNode";
 17→  if (CONDITION_TYPES.has(type)) return "conditionNode";
 18→  return "actionNode";
 19→}
 20→
 21→export function getNodeLabel(node: WorkflowNode): string {
 22→  if (node.label) return node.label;
 23→  return node.type
 24→    .split("-")
 25→    .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
 26→    .join(" ");
 27→}
 28→
 29→export interface FlowNodeData {
 30→  label: string;
 31→  nodeType: WorkflowNodeType;
 32→  config: Record<string, unknown>;
 33→  stepStatus?: WorkflowRunStepStatus;
 34→  outputPorts: string[];
 35→  selected?: boolean;
 36→  [key: string]: unknown;
 37→}
 38→
 39→export function toReactFlowGraph(
 40→  definition: WorkflowDefinition,
 41→  steps?: WorkflowRunStep[],
 42→): { nodes: Node<FlowNodeData>[]; edges: Edge[] } {
 43→  const stepMap = new Map<string, WorkflowRunStep>();
 44→  if (steps) {
 45→    for (const step of steps) {
 46→      stepMap.set(step.nodeId, step);
 47→    }
 48→  }
 49→
 50→  // Compute output ports per node from edges
 51→  const outputPortsMap = new Map<string, Set<string>>();
 52→  for (const edge of definition.edges ?? []) {
 53→    if (!outputPortsMap.has(edge.source)) {
 54→      outputPortsMap.set(edge.source, new Set());
 55→    }
 56→    outputPortsMap.get(edge.source)!.add(edge.sourcePort);
 57→  }
 58→
 59→  const nodes: Node<FlowNodeData>[] = definition.nodes.map((node) => {
 60→    const step = stepMap.get(node.id);
 61→    const ports = outputPortsMap.get(node.id);
 62→    const outputPorts = ports ? Array.from(ports) : [];
 63→    return {
 64→      id: node.id,
 65→      type: getNodeCategory(node.type),
 66→      position: { x: 0, y: 0 },
 67→      data: {
 68→        label: getNodeLabel(node),
 69→        nodeType: node.type,
 70→        config: node.config,
 71→        stepStatus: step?.status,
 72→        outputPorts,
 73→      },
 74→    };
 75→  });
 76→
 77→  const edges: Edge[] = (definition.edges ?? []).map((edge: WorkflowEdge) => {
 78→    const sourceStep = stepMap.get(edge.source);
 79→    const targetStep = stepMap.get(edge.target);
 80→    const bothCompleted = sourceStep?.status === "completed" && targetStep?.status === "completed";
 81→    return {
 82→      id: edge.id,
 83→      source: edge.source,
 84→      sourceHandle: edge.sourcePort,
 85→      target: edge.target,
 86→      targetHandle: "input",
 87→      label: edge.sourcePort !== "default" ? edge.sourcePort : undefined,
 88→      animated: bothCompleted,
 89→      style: bothCompleted ? { stroke: "var(--color-emerald-500)" } : undefined,
 90→    };
 91→  });
 92→
